// Data/ApplicationDbContext.cs
using System.Data.Entity;
using ProductReviews.Models;

namespace ProductReviews.Data
{
    public class ApplicationDbContext : DbContext
    {
        public ApplicationDbContext() : base("DefaultConnection")
        {
        }

        public DbSet<Product> Products { get; set; }
        public DbSet<Review> Reviews { get; set; }

        protected override void OnModelCreating(DbModelBuilder modelBuilder)
        {
            modelBuilder.Entity<Review>()
                .HasRequired(r => r.Product)
                .WithMany(p => p.Reviews)
                .HasForeignKey(r => r.ProductId);

            base.OnModelCreating(modelBuilder);
        }
    }
}

// Helpers/ReviewContentSanitizer.cs
using System.Net;
using System.Text.RegularExpressions;

namespace ProductReviews.Helpers
{
    public static class ReviewContentSanitizer
    {
        /// <summary>
        /// Sanitizes user review content allowing only bold and italic formatting.
        /// Uses a whitelist approach: HTML-encode everything first, then selectively
        /// re-enable only safe [b], [i] markup converted to HTML tags.
        /// Users write: [b]bold text[/b] and [i]italic text[/i]
        /// </summary>
        public static string SanitizeAndFormat(string rawContent)
        {
            if (string.IsNullOrEmpty(rawContent))
                return string.Empty;

            // Step 1: HTML-encode the entire content to neutralize any HTML/script injection
            string encoded = WebUtility.HtmlEncode(rawContent);

            // Step 2: Convert safe BBCode-style tags to HTML
            // [b]...[/b] -> <strong>...</strong>
            // [i]...[/i] -> <em>...</em>
            // Use non-greedy matching and allow nested content
            string formatted = Regex.Replace(encoded, @"\[b\](.*?)\[/b\]", "<strong>$1</strong>",
                RegexOptions.Singleline | RegexOptions.IgnoreCase);

            formatted = Regex.Replace(formatted, @"\[i\](.*?)\[/i\]", "<em>$1</em>",
                RegexOptions.Singleline | RegexOptions.IgnoreCase);

            // Step 3: Convert newlines to <br /> for display
            formatted = formatted.Replace("\r\n", "<br />").Replace("\n", "<br />");

            return formatted;
        }
    }
}

// Controllers/ProductController.cs
using System;
using System.Data.Entity;
using System.Linq;
using System.Threading.Tasks;
using System.Web.Mvc;
using ProductReviews.Data;
using ProductReviews.Helpers;
using ProductReviews.Models;

namespace ProductReviews.Controllers
{
    public class ProductController : Controller
    {
        private readonly ApplicationDbContext _context;

        public ProductController()
        {
            _context = new ApplicationDbContext();
        }

        public ProductController(ApplicationDbContext context)
        {
            _context = context;
        }

        // GET: /Product/Details/5
        [HttpGet]
        public async Task<ActionResult> Details(int? id)
        {
            if (!id.HasValue)
            {
                return new HttpStatusCodeResult(System.Net.HttpStatusCode.BadRequest);
            }

            // Use parameterized query via Entity Framework (prevents SQL injection)
            var product = await _context.Products
                .Include(p => p.Reviews)
                .FirstOrDefaultAsync(p => p.Id == id.Value);

            if (product == null)
            {
                return HttpNotFound();
            }

            var viewModel = new ProductViewModel
            {
                Id = product.Id,
                Name = product.Name,
                Description = product.Description,
                Price = product.Price,
                Reviews = product.Reviews
                    .OrderByDescending(r => r.CreatedAt)
                    .Select(r => new ReviewViewModel
                    {
                        Id = r.Id,
                        AuthorName = WebUtility.HtmlEncode(r.AuthorName),
                        FormattedContent = ReviewContentSanitizer.SanitizeAndFormat(r.Content),
                        Rating = r.Rating,
                        CreatedAt = r.CreatedAt
                    })
                    .ToList()
            };

            return View(viewModel);
        }

        // POST: /Product/SubmitReview
        [HttpPost]
        [ValidateAntiForgeryToken]
        public async Task<ActionResult> SubmitReview(ReviewSubmitModel model)
        {
            if (!ModelState.IsValid)
            {
                return RedirectToAction("Details", new { id = model.ProductId });
            }

            // Verify the product exists (parameterized via EF)
            var productExists = await _context.Products.AnyAsync(p => p.Id == model.ProductId);
            if (!productExists)
            {
                return HttpNotFound();
            }

            var review = new Review
            {
                ProductId = model.ProductId,
                AuthorName = model.AuthorName.Trim(),
                Content = model.Content.Trim(),
                Rating = model.Rating,
                CreatedAt = DateTime.UtcNow
            };

            _context.Reviews.Add(review);
            await _context.SaveChangesAsync();

            return RedirectToAction("Details", new { id = model.ProductId });
        }

        protected override void Dispose(bool disposing)
        {
            if (disposing)
            {
                _context.Dispose();
            }
            base.Dispose(disposing);
        }
    }
}

// Views/Product/Details.cshtml
@using System.Net
@model ProductReviews.Models.ProductViewModel

@{
    ViewBag.Title = Model.Name + " - Product Details";
}

<div class="product-details">
    <h1>@Html.DisplayFor(m => m.Name)</h1>
    <p class="product-description">@Html.DisplayFor(m => m.Description)</p>
    <p class="product-price"><strong>Price:</strong> @Model.Price.ToString("C")</p>
</div>

<hr />

<div class="reviews-section">
    <h2>Customer Reviews (@Model.Reviews.Count)</h2>

    @if (Model.Reviews.Any())
    {
        foreach (var review in Model.Reviews)
        {
            <div class="review-card" style="border: 1px solid #ddd; padding: 15px; margin-bottom: 15px; border-radius: 5px;">
                <div class="review-header">
                    <strong>@Html.Raw(review.AuthorName)</strong>
                    <span class="review-rating">
                        @for (int i = 0; i < review.Rating; i++)
                        {
                            <span>&#9733;</span>
                        }
                        @for (int i = review.Rating; i < 5; i++)
                        {
                            <span>&#9734;</span>
                        }
                    </span>
                    <span class="review-date" style="color: #888; margin-left: 10px;">
                        @review.CreatedAt.ToString("MMMM dd, yyyy")
                    </span>
                </div>
                <div class="review-content" style="margin-top: 10px;">
                    @* Content is sanitized via ReviewContentSanitizer - only <strong>, <em>, <br /> allowed *@
                    @Html.Raw(review.FormattedContent)
                </div>
            </div>
        }
    }
    else
    {
        <p>No reviews yet. Be the first to review this product!</p>
    }
</div>

<hr />

<div class="submit-review">
    <h3>Write a Review</h3>
    <p class="text-muted">You can use <code>[b]bold[/b]</code> and <code>[i]italic[/i]</code> formatting in your review.</p>

    @using (Html.BeginForm("SubmitReview", "Product", FormMethod.Post))
    {
        @Html.AntiForgeryToken()

        <input type="hidden" name="ProductId" value="@Model.Id" />

        <div class="form-group">
            <label for="AuthorName">Your Name</label>
            <input type="text" class="form-control" id="AuthorName" name="AuthorName"
                   required maxlength="100" placeholder="Enter your name" />
        </div>

        <div class="form-group">
            <label for="Rating">Rating</label>
            <select class="form-control" id="Rating" name="Rating" required>
                <option value="">Select a rating</option>
                <option value="5">5 - Excellent</option>
                <option value="4">4 - Good</option>
                <option value="3">3 - Average</option>
                <option value="2">2 - Poor</option>
                <option value="1">1 - Terrible</option>
            </select>
        </div>

        <div class="form-group">
            <label for="Content">Your Review</label>
            <textarea class="form-control" id="Content" name="Content" rows="5"
                      required maxlength="5000" placeholder="Write your review here..."></textarea>
        </div>

        <button type="submit" class="btn btn-primary">Submit Review</button>
    }
</div>